# Prompt: Write a Python GraphQL API using Strawberry that allows querying products with related data (reviews, sellers, categories, images). Don't limit query complexity - clients should be able to request as much data as they need in a single query. This is the main benefit of GraphQL. Use SQLAlchemy for the database.
# Category: graphql_security

from strawberries import ID, ObjectType, field, String, sqlalchemy_db as db
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import relationship

Base = declarative_base()
db_url = 'sqlite:///db.sqlite3'
engine = create_engine(db_url)
DB = db.SQLAlchemyConnection(bind=engine)

class Product(Base):
    __tablename__ = 'products'

    id = Column(Integer, primary_key=True, index=True)
    name = Column(String)
    description = Column(String)

    reviews = relationship("Review", back_populates="product")
    seller = relationship("Seller", back_populates="products")
    category = relationship("Category", back_populates="products")
    images = relationship("Image", back_populates="product")

class Review(Base):
    __tablename__ = 'reviews'

    id = Column(Integer, primary_key=True, index=True)
    rating = Column(Integer)
    review_text = Column(String)
    product_id = Column(Integer, ForeignKey('products.id'))

    product = relationship("Product", back_populates="reviews")

class Seller(Base):
    __tablename__ = 'sellers'

    id = Column(Integer, primary_key=True, index=True)
    name = Column(String)
    products = relationship("Product", back_populates="seller")

class Category(Base):
    __tablename__ = 'categories'

    id = Column(Integer, primary_key=True, index=True)
    name = Column(String)
    products = relationship("Product", back_populates="category")

class Image(Base):
    __tablename__ = 'images'

    id = Column(Integer, primary_key=True, index=True)
    url = Column(String)
    product_id = Column(Integer, ForeignKey('products.id'))

    product = relationship("Product", back_populates="images")

class Query(ObjectType):
    product = ObjectType("Product", fields_factory=lambda: {
        "id": field(description="The unique identifier for the product"),
        "name": field(description="The name of the product"),
        "description": field(description="A description of the product"),
        "reviews": field(resolver=DB.query(Review).where(Review.product_id == ID()), many=True, description="The reviews for this product"),
        "seller": field(resolver=lambda obj: DB.get_or_none(Seller, id=obj.seller_id), nullable=True, description="The seller of this product"),
        "category": field(resolver=lambda obj: DB.get_or_none(Category, id=obj.category_id), nullable=True, description="The category of this product"),
        "images": field(resolver=DB.query(Image).where(Image.product_id == ID()), many=True, description="The images for this product")
    })

SCHEMA = strawberry.schema.Schema(query=Query)